#!/usr/bin/env node
/**
 * Build agent-inventory table — generates Section J of `docs/AGENT-USAGE.md`
 * for the @bleizlabs/ui Agent Cheat-Sheet (0.25.0+).
 *
 * Reads `components/manifest.json` (must be up-to-date — run
 * `npm run build:manifest` first), emits a markdown table into a marked
 * region in the target doc:
 *
 *   <!-- INVENTORY:START — auto-generated by scripts/build-agent-inventory.mjs. Do not edit by hand. -->
 *   | Component | Category | Client? | Import | One-line summary |
 *   |---|---|---|---|---|
 *   | Card | display | no | `import { Card } from '@bleizlabs/ui'` | Card — surface container atom… |
 *   ...
 *   <!-- INVENTORY:END -->
 *
 * Prose around the markers is preserved — only between markers gets
 * regenerated. Script aborts if markers are missing (operator must add the
 * markers when authoring the section first time).
 *
 * Inventory covers `manifest.json` `components` array only (106 at audit
 * time 2026-05-13). Utilities (Slot/cn/mergeRefs/VisuallyHidden) and
 * typesOnly excluded — agents needing utility helpers read JSDoc directly.
 *
 * Sort: categories in `manifest.json` `categories` insertion order
 * (already alphabetised by build-component-manifest.mjs categoryOrder
 * constant: layout → typography → display → interactive → feedback →
 * specialized → molecules → presets → complex). Within each category:
 * alphabetical by family name.
 *
 * Run: `node scripts/build-agent-inventory.mjs [--target <path>]`.
 * Default `--target` is `docs/AGENT-USAGE.md`. Exits 0 on success, 1 on
 * any error (missing manifest, missing markers, write failure).
 */

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const MANIFEST = path.join(ROOT, 'components', 'manifest.json');
const DEFAULT_TARGET = path.join(ROOT, 'docs', 'AGENT-USAGE.md');

const MARKER_START =
  '<!-- INVENTORY:START — auto-generated by scripts/build-agent-inventory.mjs. Do not edit by hand. -->';
const MARKER_END = '<!-- INVENTORY:END -->';

function fail(msg) {
  console.error(`[build-agent-inventory] ${msg}`);
  process.exit(1);
}

function parseArgs(argv) {
  const args = { target: DEFAULT_TARGET };
  for (let i = 2; i < argv.length; i++) {
    if (argv[i] === '--target' && argv[i + 1]) {
      args.target = path.resolve(argv[i + 1]);
      i++;
    }
  }
  return args;
}

const { target } = parseArgs(process.argv);

if (!fs.existsSync(MANIFEST)) {
  fail(`Missing manifest: ${MANIFEST}. Run \`npm run build:manifest\` first.`);
}
if (!fs.existsSync(target)) {
  fail(
    `Missing target doc: ${target}. Author the doc with INVENTORY markers before running this script.`,
  );
}

const manifest = JSON.parse(fs.readFileSync(MANIFEST, 'utf8'));
if (!Array.isArray(manifest.components) || manifest.components.length === 0) {
  fail('Manifest has no `components` array or it is empty.');
}

// Pick primary export name for the Import column. Compound components ship
// multiple exports under one family — the family name itself is the import
// name in nearly all cases (Card, Form, Dialog, etc.). When the family name
// does NOT appear in exports[] (rare — e.g., Toast family's primary export
// is `Toaster`), fall back to the first export.
function importName(family) {
  if (family.exports.includes(family.family)) return family.family;
  return family.exports[0] ?? family.family;
}

function escapeMd(s) {
  // Escape pipe (table delimiter) + backtick (inline code in summary text).
  return String(s).replace(/\|/g, '\\|');
}

function clientCellLabel(isClient) {
  return isClient ? 'yes' : 'no';
}

const headerRows = [
  '| Component | Category | Client? | Import | One-line summary |',
  '|---|---|---|---|---|',
];

const rows = manifest.components.map((c) => {
  const importLine = `\`import { ${importName(c)} } from '@bleizlabs/ui'\``;
  const summary = c.summary || `${c.family} — (no JSDoc summary)`;
  return `| \`${c.family}\` | ${c.category} | ${clientCellLabel(c.isClient)} | ${importLine} | ${escapeMd(summary)} |`;
});

const tableBlock = [
  MARKER_START,
  `<!-- Generated from components/manifest.json at lib version ${manifest.libVersion}. Component count: ${manifest.components.length}. -->`,
  '',
  ...headerRows,
  ...rows,
  '',
  MARKER_END,
].join('\n');

const targetSrc = fs.readFileSync(target, 'utf8');
const startIdx = targetSrc.indexOf(MARKER_START);
const endIdx = targetSrc.indexOf(MARKER_END);
if (startIdx === -1) {
  fail(
    `Target doc missing INVENTORY:START marker.\n` +
      `Add this line where the table should appear:\n  ${MARKER_START}\n  ${MARKER_END}\n` +
      `Target: ${target}`,
  );
}
if (endIdx === -1 || endIdx < startIdx) {
  fail(
    `Target doc has INVENTORY:START but missing INVENTORY:END marker (or markers in wrong order). Target: ${target}`,
  );
}

const before = targetSrc.slice(0, startIdx);
const after = targetSrc.slice(endIdx + MARKER_END.length);
const next = before + tableBlock + after;

fs.writeFileSync(target, next, 'utf8');

const relTarget = path.relative(ROOT, target);
console.log(`[build-agent-inventory] OK`);
console.log(`  target:      ${relTarget}`);
console.log(`  components:  ${manifest.components.length}`);
console.log(`  libVersion:  ${manifest.libVersion}`);
console.log(`  rows written between INVENTORY:START/END markers.`);
